self.addEventListener("push",t=>{let e=JSON.parse(t?.data?.text()||"{}");t.waitUntil(self.registration.showNotification(e.title||"في السكة",{body:e.body||"لديك إشعار جديد",icon:e.icon||"/icon512_maskable.png",badge:"/icon512_maskable.png",vibrate:[500,250,500,250,500,250,500,250,500],requireInteraction:!0,silent:!1,data:e.data||{}}))}),self.addEventListener("notificationclick",t=>{t.notification.close();let e=t.notification.data?.url||"/notifications";t.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{if(t.length>0){let i=t[0];for(let e=0;e<t.length;e++)t[e].focused&&(i=t[e]);return"navigate"in i&&i.navigate(e),i.focus()}return self.clients.openWindow(e)}))});